    ('EALC-J 301', 'THIRD YEAR JAPANESE 1', '1452', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–1:35 PM', 'GA 1118 LH 035 GA 1118', 'Jae Takeuchi', 7, 'Lecture', 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES, LINDLEY HALL', ARRAY[]::TEXT[], 'Review of grammatical points acquired in the first and second year Japanese. More advanced level of speaking, reading, writing, and listening proficiency.', ARRAY[]::TEXT[], NULL),
