    ('EALC-J 311', 'JAPANESE LANGUAGE PRACTICE: HUMANITIES', '29666', 'Class Status', 'W Wednesday 11:35 AM–12:25 PM', 'ED 1201', 'Shoichi Ueda', 1, NULL, 'Lecture', '1', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'For students who want simultaneously to improve their content knowledge and language skills by discussing Japanese literature, arts, music, or other humanities.', ARRAY[]::TEXT[], NULL),
    ('EALC-J 311', 'JAPANESE LANGUAGE PRACTICE: HUMANITIES', '29667', 'Class Status', 'W Wednesday 11:35 AM–12:25 PM', 'ED 1201', 'Shoichi Ueda', 1, NULL, 'Lecture', '1', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'For students who want simultaneously to improve their content knowledge and language skills by discussing Japanese literature, arts, music, or other humanities.', ARRAY[]::TEXT[], NULL),
    ('EALC-J 401', 'FOURTH-YEAR JAPANESE I', '13939', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'GA 0005', 'Misako Matsubara', 1, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Emphasis on advanced reading skills.', ARRAY[]::TEXT[], NULL),
    ('EALC-J 421', 'INTRODUCTION TO JAPANESE LINGUISTICS', '14217', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'GA 0013', 'Alan Reiser', 2, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'A descriptive survey of issues in Japanese linguistics. Topics will include syntax, phonology/phonetics, and semantics/pragmatics of Japanese.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('EALC-J 425', 'TEACHING JAPANESE LANGUAGE', '9468', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'GA 2067', 'Jae Takeuchi', 13, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Taught in seminar-practice format, the course examines contemporary paradigms of foreign language instruction, identifies critical issues in language pedagogy, and explores various techniques of teaching the four language skills (speaking, listening, reading, writing). Active participation mandatory.', ARRAY[]::TEXT[], NULL),
    ('EALC-J 461', 'LITERARY JAPANESE', '31586', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 221', 'Ryan Hintzman', 3, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'A basic outline of the varieties of written Japanese known collectively as bungotal or "literary Japanese." Initial emphasis is on reading and close rhetorical and grammatical analysis of genres from the tenth through fifteenth centuries, with later attention to other periods and texts.', ARRAY[]::TEXT[], NULL),
    ('EALC-J 506', 'LITERARY JAPANESE I', '31587', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 221', 'Ryan Hintzman', 3, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'A basic outline of the varieties of written Japanese known collectively as bungotal or "literary Japanese." Initial emphasis on reading and close rhetorical and grammatical analysis of genres from the tenth through fifteenth centuries, with later attention to other periods and texts.', ARRAY[]::TEXT[], NULL),
    ('EALC-J 520', 'INTRODUCTION TO JAPANESE LINGUISTICS', '14214', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'GA 0013', 'Alan Reiser', 2, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Linguistic phenomena in Japanese from the descriptive and comparative points of view. Development of linguistic problem-solving skills, including consideration of sociological issues.', ARRAY[]::TEXT[], NULL),
    ('EALC-J 525', 'TEACHING JAPANESE AS A FOREIGN/SECOND LANGUAGE', '9488', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'GA 2067', 'Jae Takeuchi', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course is for graduate and advanced undergraduate students interested in acquiring knowledge, skills, and experience in teaching Japanese as a foreign language. Taught in a seminar-practice format, it examines the contemporary paradigms of foreign language instruction in terms of, speaking, listening, reading and writing skills. Active participation is mandatory.', ARRAY[]::TEXT[], NULL),
    ('EALC-J 527', 'PRACTICUM IN JAPANESE LANGUAGE PEDAGOGY', '11377', 'Class Status', NULL, NULL, 'Jae Takeuchi', 8, NULL, 'Lecture', '3', NULL, ARRAY[]::TEXT[], 'Supervised application of language pedagogy. In an actual classroom, students will apply the theories, paradigms, and approaches to language learning they have studied. Practicum experience developed in consultation with the advisor, with approval of the Director of Graduate Studies.', ARRAY[]::TEXT[], NULL),
    ('EALC-J 533', 'THIRD YEAR JAPANESE I', '3761', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–1:35 PM', 'GA 1118 LH 035 GA 1118', 'Jae Takeuchi', 7, 'Lecture', 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES, LINDLEY HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EALC-J 533', 'THIRD YEAR JAPANESE I', '9298', 'Class Status', 'MWF Monday, Wednesday, Friday 1:55 PM–2:45 PM', 'BH 317', 'Jae Takeuchi', 3, 'Drill', 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES, LINDLEY HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
