    ('EALC-J 598', 'PEDOGOGY PROJECT', '3288', 'Class Status', NULL, NULL, 'Jae Takeuchi', 10, NULL, 'Research', '1–4', NULL, ARRAY[]::TEXT[], 'Demonstration of pedagogical understanding and skills. The project may take either of two forms: empirical study of pedagogical issues or significant materials development (e.g., set of course materials, course website, multimedia learning modules, testing instruments). Developed in consultation with the advisor, with approval of the Director of Graduate Studies.', ARRAY[]::TEXT[], NULL),
    ('EALC-J 701', 'M. A. THESIS', '1453', 'Class Status', NULL, NULL, 'Nick Vogt', 10, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
