    ('EALC-K 211', 'SECOND YEAR KOREAN CONVERSATION PRACTICE I', '34285', 'Class Status', 'M Monday 3:10 PM–4:00 PM', 'ED 3284', 'Jungwon Yoo', 7, NULL, 'Practice', '1', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Improves students'' Korean speaking skills to the Intermediate proficiency level. Engages students in various speaking activities aligned with the Second Year Korean I course.', ARRAY[]::TEXT[], NULL),
    ('EALC-K 301', 'THIRD YEAR KOREAN 1', '6649', 'Class Status', 'TuTh Tuesday, Thursday 1:55 PM–2:45 PM', 'GA 1134', 'Weejeong Jeong', 7, 'Lecture', 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Develops proficiency in all four language skills: speaking, listening, reading, and writing. Studies short passages on a variety of topics. Enhances the ability to extract main ideas from the texts for in-class discussion.', ARRAY[]::TEXT[], NULL),
    ('EALC-K 301', 'THIRD YEAR KOREAN 1', '1465', 'Class Status', 'MWF Monday, Wednesday, Friday 1:55 PM–2:45 PM', 'AC C101', 'Weejeong Jeong', 7, 'Drill', 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Develops proficiency in all four language skills: speaking, listening, reading, and writing. Studies short passages on a variety of topics. Enhances the ability to extract main ideas from the texts for in-class discussion.', ARRAY[]::TEXT[], NULL),
    ('EALC-K 301', 'THIRD YEAR KOREAN 1', '8979', 'Closed', 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM', 'AC C116', 'Weejeong Jeong', 0, 'Drill', 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Develops proficiency in all four language skills: speaking, listening, reading, and writing. Studies short passages on a variety of topics. Enhances the ability to extract main ideas from the texts for in-class discussion.', ARRAY[]::TEXT[], NULL),
    ('EALC-K 311', 'THIRD YEAR KOREAN CONVERSATION PRACTICE I', '34286', 'Class Status', 'Th Thursday 12:45 PM–1:35 PM', 'ED 2280', 'Joungmok Lee', 2, NULL, 'Practice', '1', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Students participate in various Korean speaking activities aligned with the Third Year Korean I course.', ARRAY[]::TEXT[], NULL),
    ('EALC-K 321', 'BUSINESS KOREAN I', '33361', 'Class Status', 'MWF Monday, Wednesday, Friday 11:25 AM–12:25 PM', 'JH A107', 'Jiyoung Kim', 9, NULL, 'Lecture', '2', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Develops fundamental business Korean skills using professional tools such as letters and presentations. Introduces key business expressions and job search process, including interview techniques tailored to the Korean business context. Explores current issues in Korea''s economy, society, and culture to enhance language proficiency and cultural understanding.', ARRAY[]::TEXT[], NULL),
    ('EALC-K 401', 'FOURTH YEAR KOREAN I', '7807', 'Class Status', 'MWF Monday, Wednesday, Friday 1:55 PM–2:45 PM', 'WY 111', 'Jiyoung Kim', 1, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'Emphasis on advanced reading skills, featuring authentic writings such as newspaper editorials, essays, movie scenarios, and TV news.', ARRAY[]::TEXT[], NULL),
    ('EALC-K 501', 'FOURTH-YEAR KOREAN I', '7808', 'Class Status', 'MWF Monday, Wednesday, Friday 1:55 PM–2:45 PM', 'WY 111', 'Jiyoung Kim', 1, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'Emphasis on advanced reading skills, featuring authentic writings such as newspaper editorials, essays, movie scenarios, and TV news.', ARRAY[]::TEXT[], NULL),
    ('EALC-K 527', 'PRACTICUM IN KOREAN LANGUAGE PEDAGOGY', '34289', 'Class Status', NULL, NULL, 'Hyo Lee', 3, NULL, 'Lecture', '2–3', NULL, ARRAY[]::TEXT[], 'Supervised applications of language pedagogy. In an actual classroom, students will apply the theories, paradigms, and approaches to language learning they have studied. Practicum experience developed in consultation with the advisor, with approval of the Director of Graduate Studies.', ARRAY[]::TEXT[], NULL),
    ('EALC-K 533', 'THIRD YEAR KOREAN 1', '10749', 'Class Status', 'TuTh Tuesday, Thursday 1:55 PM–2:45 PM', 'GA 1134', 'Weejeong Jeong', 7, 'Lecture', 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Primarily designed to develop and enhance students'' reading ability through a variety of written materials; considerable emphasis on writing and conversational skills. Some 200 Chinese characters that are frequently used in Korean newspapers may be taught.', ARRAY[]::TEXT[], NULL),
    ('EALC-K 533', 'THIRD YEAR KOREAN 1', '10750', 'Class Status', 'MWF Monday, Wednesday, Friday 1:55 PM–2:45 PM', 'AC C101', 'Weejeong Jeong', 7, 'Drill', 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Primarily designed to develop and enhance students'' reading ability through a variety of written materials; considerable emphasis on writing and conversational skills. Some 200 Chinese characters that are frequently used in Korean newspapers may be taught.', ARRAY[]::TEXT[], NULL),
    ('EALC-K 533', 'THIRD YEAR KOREAN 1', '10751', 'Closed', 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM', 'AC C116', 'Weejeong Jeong', 0, 'Drill', 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Primarily designed to develop and enhance students'' reading ability through a variety of written materials; considerable emphasis on writing and conversational skills. Some 200 Chinese characters that are frequently used in Korean newspapers may be taught.', ARRAY[]::TEXT[], NULL),
    ('EALC-K 535', 'KOREAN CURRICULUM AND MATERIAL DESIGN', '34146', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'ED 1250', 'Hyo Lee', 2, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'For students interested in exploring the theories, issues, and principles of language curriculum design and acquiring practical experience of applying various syllabus frameworks to design sample Korean materials. Emphasis on developing students'' ability to analyze and synthesize factors contributing to an effective language learning program.', ARRAY[]::TEXT[], NULL),
    ('EALC-K 598', 'PEDAGOGY PROJECT', '34290', 'Class Status', NULL, NULL, 'Hyo Lee', 5, NULL, 'Lecture', '1–4', NULL, ARRAY[]::TEXT[], 'Demonstration of pedagogical understanding and skills. The project may take either of two forms: empirical study of pedagogical issues or significant materials development (e.g., set of course materials, course website, multimedia learning modules, testing instruments). Developed in consultation with the advisor, with approval of the Director of Graduate Studies.', ARRAY[]::TEXT[], NULL),
    ('EALC-X 490', 'INDIVIDUAL READINGS', '11910', 'Class Status', NULL, NULL, 'Yea-Fen Chen', 2, NULL, 'Readings', '3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EALC-X 490', 'INDIVIDUAL READINGS', '1432', 'Class Status', NULL, NULL, 'Jiyoung Kim', 2, NULL, 'Readings', '3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EALC-X 490', 'INDIVIDUAL READINGS', '11906', 'Class Status', NULL, NULL, 'Seung-kyung Kim', 1, NULL, 'Readings', '3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EAS-A 332', 'ATMOSPHERIC THERMODYNAMICS & CLOUD PROCESSES', '11986', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'GY 4069', 'Paul Staten', 9, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Earth''s weather and climate are controlled by how heat and moisture move in the atmosphere. In this course, students learn and apply the basic physical laws that govern those processes. Topics include thermodynamic laws, principles of atmospheric stability, phase changes of water, nucleation of cloud droplets and the growth of clouds, and the use of common meteorological tools and data to interpret cloud and precipitation behavior.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('EAS-A 339', 'WEATHER ANALYSIS AND FORECASTING', '13194', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'GY 2033', 'Cody Kirkpatrick', 13, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Analysis and interpretation of meteorological data with a focus on forecasting applications for the mid-latitudes. Students learn the practical skills that weather forecasters use.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('EAS-A 340', 'PHYSICAL METEOROLOGY AND CLIMATOLOGY', '13432', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'SB 005', 'Scott Robeson', 1, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Provides an introduction to the physical basis of Earth''s atmosphere and climate system from global to local scales, emphasizing physical processes and properties. Analyzes surface energy and water balances in varied landscapes. Covers issues related to climate change.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('EAS-A 476', 'CLIMATE CHANGE SCIENCE', '13972', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'GY 5051', 'Ben Kravitz', 0, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Evidence for and theories of climate change over a range of time scales. Sources of natural climate forcing are presented, historical evolution of climate change is quantified, and model tools and climate projections are presented along with analyses of climate change impacts.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit
Class uses IU eTexts
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('EAS-E 104', 'EVOLUTION OF THE EARTH', '8528', 'Closed', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'GY 1045', 'Jackson Njau', 0, 'Lecture', 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Earth''s history interpreted through 4.5 billion years. Deductive approach to understanding the significance of rocks and fossils and reconstructing the plate-tectonic origin of mountains, continents, and ocean basins. A survey of events in earth''s evolution relevant to contemporary environmental concerns. Two lectures and one laboratory each week.', ARRAY['IUB GenEd N&M credit - Natural Science
COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
