    ('EAS-E 226', 'EARTH PROCESSES', '9946', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'GY 2049', 'Douglas Edmonds, Kaj Johnson', 1, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Introduction to the processes that shape our planet, the composition and structure of Earth, and the erosion and deposition of sediments at the surface. Study of processes ranging from forces driving plate motion, fluid flow in and on the earth, crustal deformation and mountain building, erosion of source terrain, the transport system, and the depositional record.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('EAS-E 316', 'MINERAL RESOURCES', '29297', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'GY 2049', 'Shelby Rader', 18, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Origin of petroleum, coal, industrial minerals, and ore deposits: reserves, resources, and future needs; history, economic and environmental considerations, national minerals policy, and international aspects of energy and raw materials distribution.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit
Class uses IU eTexts'], NULL),
    ('EAS-E 351', 'ELEMENTS OF HYDROLOGY', '29301', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'GY 2049', 'Brian Yanites', 1, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'An intensive survey of Earth''s water resources, focusing on the first principles that govern surface water and groundwater and the techniques used in the field for hydrology.', ARRAY[]::TEXT[], NULL),
    ('EAS-E 418', 'IGNEOUS AND METAMORPHIC PETROLOGY', '29299', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'GY 2064', 'Elizabeth Kenderes', 5, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Covers the petrogenesis of igneous and metamorphic rock. Emphasizes the application of modern petrographic, mineralogic, geochemical and phase equilibria techniques to the solution of relevant petrologic problems through lectures and lab work.', ARRAY[]::TEXT[], NULL),
    ('EAS-E 490', 'UNDERGRADUATE SEMINAR', '34152', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'GY 2049', 'Chen Zhu', 12, NULL, 'Seminar', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EAS-E 499', 'HONORS RESEARCH IN GEOSCIENCES', '14741', 'Class Status', NULL, NULL, 'Brian Yanites', 1, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EAS-E 499', 'HONORS RESEARCH IN GEOSCIENCES', '14857', 'Class Status', NULL, 'HD TBA', 'Douglas Edmonds', 2, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EAS-G 540', 'PHYSICAL METEOROLOGY AND CLIMATOLOGY', '13658', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'SB 005', 'Scott Robeson', 1, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Introduction to the physical basis of Earth''s atmosphere and climate system from global to local scales, emphasizing physical processes and properties. Analysis of surface energy and water balances in varied landscapes.', ARRAY[]::TEXT[], NULL),
    ('EAS-G 559', 'EARTH SURFACE PROCESSES', '30233', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'GY 5051', 'Douglas Edmonds', 5, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'In this course, we will learn how the movement of rock and sediment shapes mountains, drainage basins, hillslopes, rivers, and coastlines. Lectures are based on conservation of mass and momentum, Newtonian and non-Newtonian fluid mechanics, sediment transport, and tectonics. We will apply these concepts in the field and through modeling.', ARRAY[]::TEXT[], NULL),
    ('EAS-G 561', 'PALEOECOLOGY', '30145', 'Class Status', 'F Friday 10:25 AM–12:55 PM', 'GY 1042', 'Jackson Njau', 1, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Relationships between modern and fossil organisms and their physical, chemical, and biological environments; emphasis on techniques for interpreting past environmental conditions.', ARRAY[]::TEXT[], NULL),
    ('EAS-G 590', 'PROFESSIONAL DEVELOPMENT IN THE GEOSCIENCES', '10081', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'GY 2029', 'Brian Yanites, Ben Kravitz', 7, NULL, 'Seminar', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Introductory seminar for incoming graduate students in Earth and Atmospheric Sciences designed to help transition from undergraduates to research scientists, focusing on practical skills required for success. Engages students in broadening perspectives of the geosciences via the departmental colloquiums, and practical aspects of research activities including writing publications and proposals.', ARRAY[]::TEXT[], NULL),
    ('EAS-G 612', 'INVERSE METHODS IN GEOPHYSICS', '29300', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'GY 2049', 'Kaj Johnson', 13, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Mathematical techniques infer model parameters from observed data and to appraise the reliability of the results. Linear regression. Error propagation. Singular value decomposition. Nonlinear regression. Bayesian methods. Problems will be chosen from various subdisciplines of Geosciences.', ARRAY[]::TEXT[], NULL),
    ('EAS-G 633', 'ADVANCED GEOPHYSICS SEMINAR', '15229', 'Class Status', NULL, NULL, 'Kaj Johnson, Jianhua Gong', 11, NULL, 'Lecture', '1', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
