    ('EAS-G 901', 'ADVANCED RESEARCH', '7628', 'Class Status', NULL, NULL, 'P. David Polly', 17, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('EAS-X 150', 'ASURE EARTH & ATMOSPHERIC SCIENCES RESEARCH LAB', '29974', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'GY 2049', 'Elizabeth Kenderes', 4, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'First in a two-lab sequence for students in the Arts and Sciences Undergraduate Research Experience (ASURE) program, exploring how natural disasters and climate change impact Earth systems, using tools and techniques to research changes in the landscape, atmosphere, biosphere, or solid Earth in response to natural disasters and climate change.', ARRAY[]::TEXT[], NULL),
