    ('ECON-E 303', 'SURVEY OF INTERNATIONAL ECONOMICS', '14026', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'BH 208', 'Ting Wei Chen', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Basis for and effects of international trade, commercial policy and effects of trade restrictions, balance of payments and exchange rate adjustment, international monetary systems, and fixed vs. flexible exchange rates.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('ECON-E 305', 'MONEY AND BANKING', '5479', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'GA 1100', 'Ellie Cothren', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course studies money, banks, financial markets and government monetary and financial policy. Monetary topics include the role of money in the economy, different types of money, the measurement of the money supply, the nature of monetary institutions and the conduct and impact of monetary policy. Other important topics are the special monetary and financial role of banks and the nature and goals of bank regulation. On the finance side, the main focus is the organization of financial markets, the determination of interest rates and bond prices, and the nature and purpose of government regulation of the financial system.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('ECON-E 309', 'TOPICS IN ECONOMICS', '12008', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'PY 226', 'John Schwendel', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Study of a topic area in economics. Topics will vary. Intended primarily for non-majors wanting exposure to economics beyond the introductory level.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('ECON-E 309', 'TOPICS IN ECONOMICS', '33182', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'AC C002', 'Gerhard Glomm', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Study of a topic area in economics. Topics will vary. Intended primarily for non-majors wanting exposure to economics beyond the introductory level.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('ECON-E 321', 'INTERMEDIATE MICROECONOMIC THEORY', '6020', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'LU 1001', 'Emerson Melo', 0, NULL, 'Lecture', '3', 'LUDDY CENTER FOR AI', ARRAY[]::TEXT[], 'Develops economic models of both consumer and firm behavior, including non-strategic and strategic interactions. Models of market structure and behavior focus on price and output determination and include circumstances in which markets may succeed or fail to deliver socially beneficial outcomes.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
