    ('ECON-E 327', 'GAME THEORY', '1468', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'BH 208', 'Eun Lee', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Mathematical analysis of strategic interaction. Noncooperative games played once or repeatedly, with perfect or imperfect information. Necessary condition for a solution (equilibrium) as well as sufficient conditions (refinements) cooperative games, such as bargaining and market games. Numerous applications, including experimental games.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('ECON-E 327', 'GAME THEORY', '13290', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'BH 003', 'Eun Lee', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Mathematical analysis of strategic interaction. Noncooperative games played once or repeatedly, with perfect or imperfect information. Necessary condition for a solution (equilibrium) as well as sufficient conditions (refinements) cooperative games, such as bargaining and market games. Numerous applications, including experimental games.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('ECON-E 331', 'INTERNATIONAL TRADE', '12009', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 209', 'Mostafa Beshkar', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Theories of trade pattern, positive and normative aspects of trade and trade-related policies in competitive and noncompetitive markets; effects of trade liberalization and economic integration; trade policies by developed and developing nations; international factor movements.', ARRAY['Class uses IU eTexts'], NULL),
    ('ECON-E 331', 'INTERNATIONAL TRADE', '35511', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'SY 137', 'Enakshi Bera', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Theories of trade pattern, positive and normative aspects of trade and trade-related policies in competitive and noncompetitive markets; effects of trade liberalization and economic integration; trade policies by developed and developing nations; international factor movements.', ARRAY['Class uses IU eTexts'], NULL),
    ('ECON-E 362', 'PUBLIC FINANCE-TAXATION', '13265', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 307', 'James Self', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'U.S. tax structure, income redistribution effects, and efficiency in resource allocation. Use of welfare theory and microeconomic models to evaluate particular issues.', ARRAY['Class uses IU eTexts'], NULL),
