    ('ECON-E 824', 'READINGS IN ECONOMIC THEORY', '1480', 'Class Status', NULL, NULL, 'Volodymyr Lugovskyy', 10, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ECON-E 830', 'READINGS IN INTERNATIONAL TRADE', '1481', 'Class Status', NULL, NULL, 'Volodymyr Lugovskyy', 10, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ECON-E 840', 'READINGS IN ECONOMICS OF LABOR AND HUMAN RESOURCES DEVELOPMENT', '1482', 'Class Status', NULL, NULL, 'Volodymyr Lugovskyy', 5, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ECON-E 850', 'READINGS IN MONETARY ECONOMICS', '1483', 'Class Status', NULL, NULL, 'Volodymyr Lugovskyy', 5, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ECON-E 860', 'READINGS IN PUBLIC ECONOMICS', '1484', 'Class Status', NULL, NULL, 'Volodymyr Lugovskyy', 5, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ECON-E 870', 'READINGS IN ADVANCED ECONOMETRICS', '1485', 'Class Status', NULL, NULL, 'Volodymyr Lugovskyy', 5, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ECON-E 880', 'READINGS IN INDUSTRIAL ORGANIZATION', '1486', 'Class Status', NULL, NULL, 'Volodymyr Lugovskyy', 5, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ECON-E 890', 'READINGS IN DEVELOPMENT AND ECONOMICS OF TRANSITION', '1487', 'Class Status', NULL, NULL, 'Volodymyr Lugovskyy', 5, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ECON-G 599', 'THESIS RESEARCH', '3115', 'Class Status', NULL, NULL, 'Volodymyr Lugovskyy', 15, NULL, 'Research', '0', NULL, ARRAY[]::TEXT[], 'Master''s students who have enrolled in 30 or more hours of graduate course work applicable to the degree and who have completed all other requirements of the degree except the thesis of final project of performance may enroll in G599. Requires section authorization.', ARRAY[]::TEXT[], NULL),
    ('ECON-G 901', 'ADVANCED RESEARCH', '1488', 'Class Status', NULL, NULL, 'Volodymyr Lugovskyy', 35, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('ECON-M 500', 'ANALYTICAL METHODS IN ECONOMICS', '9375', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WY 329', 'Daniela Valdivia', 10, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'Introduction to concepts, methods and analytical tools that are useful for solving household and firm maximization problems and for solving economic equilibrium problems. Issues that arise in these problems include issues of existence, uniqueness and characterization of solutions.', ARRAY[]::TEXT[], NULL),
    ('ECON-M 501', 'MICROECONOMIC THEORY I', '9377', 'Class Status', 'MW Monday, Wednesday 9:35 AM–12:50 PM', 'LH 120', 'Gustavo Torrens', 9, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Introduces students to a rigorous formulation of price theory or partial equilibrium analysis. The course will cover simple foundational models of consumer and of firm behavior under the price taking or competitive assumption. This assumption serves as a useful benchmark for all other economic models introduced throughout the program.', ARRAY[]::TEXT[], NULL),
    ('ECON-M 504', 'ECONOMETRICS I', '9376', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WY 329', 'Bo Hu', 13, NULL, 'Lecture', '4', 'WYLIE HALL', ARRAY[]::TEXT[], 'This course prepares students to understand and conduct empirical economic analyses. The course will focus on the application of Microeconometric methods. After having taken this course students should be able to critically assess empirical studies, as typically conducted in government institutions, consulting or other private sector firms.', ARRAY[]::TEXT[], NULL),
    ('ECON-M 513', 'FINANCIAL ECONOMICS', '10052', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WY 225', 'Robert Becker', 3, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'This course focuses on the asset pricing theory and to subsequently present empirics of asset pricing. Basic theories of derivative pricing such as Black-Scholes option pricing as well as CAPM, APT. Some statistical technics and numerical computational methods for asset pricing will be covered.', ARRAY['Class uses IU eTexts'], NULL),
    ('ECON-M 518', 'BIG DATA IN ECONOMICS', '11710', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'BH 005', 'Yuki Ito', 5, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'The course first provides a solid training on data management tools. Then, it introduces students into tools from the field of machine learning. Finally, it uses these tools to conduct causal inference in economic models. Applications will include prediction and causal estimation of sales, wages, stock returns and credit defaults.', ARRAY[]::TEXT[], NULL),
    ('ECON-M 524', 'FINANCIAL ECONOMETRICS', '10053', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'WY 329', 'Yoosoon Chang', 2, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'The course covers the econometrics toolboxes that are useful to analyze financial market data. The goal is to understand and implement state-of-the-art econometric methods with the data at hand, providing answers to empirical questions. Topics include stationary time series analysis, persistency, predictive regression, model selection, factor models, and advanced topics.', ARRAY[]::TEXT[], NULL),
    ('ECON-S 370', 'STATISTICAL ANALYSIS FOR BUSINESS AND ECONOMICS: HONORS', '8826', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'GY 2053', 'Nastassia Krukava', 17, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Honors course. Designed for students of superior ability. Covers same core material as ECON-E 370.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit
Class uses IU eTexts'], NULL),
    ('ECON-X 373', 'INTERNSHIP IN ECONOMICS', '1489', 'Class Status', NULL, NULL, 'Volodymyr Lugovskyy', 12, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Supervised work experience in an academic or business environment, including as a teaching assistant for undergraduate classes. Performance evaluation by a faculty mentor.', ARRAY[]::TEXT[], NULL),
    ('ECON-X 398', 'INDEPENDENT RESEARCH IN ECONOMICS', '7057', 'Class Status', NULL, NULL, 'Volodymyr Lugovskyy', 12, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Independent readings and research by special arrangement with an economics faculty mentor and the director of undergraduate studies. A research paper or other substantial writing assignments are usually required.', ARRAY[]::TEXT[], NULL),
    ('EDUC-A 308', 'LEGAL AND ETHICAL ISSUES IN EDUCATION', '3683', 'Class Status', 'M Monday 5:30 PM–6:45 PM', 'ED 1120', 'Janet Decker', 3, 'Lecture', 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Students examine legal and ethical issues in schools by (1) identifying various legal and ethical dilemmas in order to articulate and defend solutions; (2) applying constitutional, statutory, and case law; (3) increasing legal literacy including "preventative law;" and (4) discussing social justice (e.g., SES, race, nationality, religion, gender, LGBTQ+, disability).', ARRAY[]::TEXT[], NULL),
    ('EDUC-A 308', 'LEGAL AND ETHICAL ISSUES IN EDUCATION', '3685', 'Class Status', 'W Wednesday 5:30 PM–6:45 PM', 'ED 1220', 'Allie Howard', 2, 'Discussion', 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Students examine legal and ethical issues in schools by (1) identifying various legal and ethical dilemmas in order to articulate and defend solutions; (2) applying constitutional, statutory, and case law; (3) increasing legal literacy including "preventative law;" and (4) discussing social justice (e.g., SES, race, nationality, religion, gender, LGBTQ+, disability).', ARRAY[]::TEXT[], NULL),
    ('EDUC-A 308', 'LEGAL AND ETHICAL ISSUES IN EDUCATION', '3686', 'Class Status', 'W Wednesday 5:30 PM–6:45 PM', 'ED 2025', 'Janet Decker', 1, 'Discussion', 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Students examine legal and ethical issues in schools by (1) identifying various legal and ethical dilemmas in order to articulate and defend solutions; (2) applying constitutional, statutory, and case law; (3) increasing legal literacy including "preventative law;" and (4) discussing social justice (e.g., SES, race, nationality, religion, gender, LGBTQ+, disability).', ARRAY[]::TEXT[], NULL),
    ('EDUC-A 308', 'LEGAL AND ETHICAL ISSUES IN EDUCATION', '3684', 'Closed', 'W Wednesday 5:30 PM–6:45 PM', 'ED 2275', 'Hannah Levy', 0, 'Discussion', 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Students examine legal and ethical issues in schools by (1) identifying various legal and ethical dilemmas in order to articulate and defend solutions; (2) applying constitutional, statutory, and case law; (3) increasing legal literacy including "preventative law;" and (4) discussing social justice (e.g., SES, race, nationality, religion, gender, LGBTQ+, disability).', ARRAY[]::TEXT[], NULL),
    ('EDUC-A 308', 'LEGAL AND ETHICAL ISSUES IN EDUCATION', '32938', 'Class Status', 'MW Monday, Wednesday 6:30 PM–7:45 PM', 'ED 1225', 'Hannah Gahimer', 1, 'Lecture', 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Students examine legal and ethical issues in schools by (1) identifying various legal and ethical dilemmas in order to articulate and defend solutions; (2) applying constitutional, statutory, and case law; (3) increasing legal literacy including "preventative law;" and (4) discussing social justice (e.g., SES, race, nationality, religion, gender, LGBTQ+, disability).', ARRAY[]::TEXT[], NULL),
    ('EDUC-A 500', 'INTRODUCTION TO EDUCATIONAL LEADERSHIP', '12759', 'Class Status', NULL, 'WB WEB', 'Frank Perrone', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course entails an introduction to the history, philosophy, and social aspects of educational leadership. It reviews relevant theories of administration; the historical role of administration in schools; and the political, social, economic, and philosophical frameworks that have informed administration.', ARRAY[]::TEXT[], NULL),
    ('EDUC-A 510', 'SCHOOL COMMUNITY RELATIONS', '12079', 'Class Status', NULL, 'WB WEB', 'Nikki Woodson', 3, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course investigates characteristics of the community school, including the multicultural quality of the community. It also explores adapting the educational program to community needs, using community resources in instruction, and planning school-community relations programs.', ARRAY[]::TEXT[], NULL),
    ('EDUC-A 515', 'INSTRUCTIONAL LEADERSHIP, SUPERVISION, AND DEVELOPMENT', '7111', 'Class Status', NULL, 'WB WEB', 'Chris Finley', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Course examines instructional leadership in K-12 school settings with a specific emphasis on the improvement of teaching. Content includes teacher supervision, evaluation and development. Questions related to teacher hiring and recruitment, professional learning, curriculum development, and coaching to support instructional improvement are also addressed.', ARRAY[]::TEXT[], NULL),
    ('EDUC-A 590', 'INDEPENDENT STUDY IN EDUCATIONAL LEADERSHIP', '13122', 'Closed', NULL, NULL, 'Frank Perrone', 0, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Individual research or study with School Administration faculty member, arranged in advance of registration. A one or two page written proposal should be submitted to the instructor during the first week of the term, specifying the scope of the project, project activities, meeting times, completion date, and student products.', ARRAY[]::TEXT[], NULL),
    ('EDUC-A 608', 'LEGAL AND ETHICAL PERSPECTIVES ON EDUCATION', '30400', 'Closed', NULL, 'WB WEB', 'Hannah Gahimer', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course entails an overview of the legal framework affecting the organization and administration of public schools, including church-state issues, the rights of students and teachers, conditions of employment, teacher organizations, special education, student discipline, tort liability, school finance, and desegregation.', ARRAY[]::TEXT[], NULL),
    ('EDUC-A 624', 'EDUCATIONAL LEADERSHIP: THE PRINCIPALSHIP K-12', '30404', 'Class Status', NULL, 'WB WEB', 'Melissa Brisco', 6, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course engages students in a dialogue around building a professional learning community leading to instructional program coherence committed to the success of all students. Students complete their leadership platform as a part of this course.', ARRAY[]::TEXT[], NULL),
    ('EDUC-A 629', 'CONTINUOUS SCHOOL IMPROVEMENT AND DATA-INFORMED DECISION-MAKING', '6126', 'Class Status', NULL, 'WB WEB', 'Teresa Brown', 5, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Prepares educational leaders to lead continuous school improvement by critically collecting, analyzing, evaluating, and using various forms of data to improve teaching, learning, and decision-making in schools.', ARRAY[]::TEXT[], NULL),
    ('EDUC-A 629', 'CONTINUOUS SCHOOL IMPROVEMENT AND DATA-INFORMED DECISION-MAKING', '33130', 'Class Status', NULL, NULL, 'Lynn Reed', 14, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Prepares educational leaders to lead continuous school improvement by critically collecting, analyzing, evaluating, and using various forms of data to improve teaching, learning, and decision-making in schools.', ARRAY[]::TEXT[], NULL),
    ('EDUC-A 635', 'PUBLIC SCHOOL BUDGETING AND ACCOUNTING', '12080', 'Class Status', NULL, 'WB WEB', 'Michele Moore', 7, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course explores the normative and positive aspects of financing K-12 public education. After a rigorous introduction to the foundation of school finance theory, the course investigates the concepts and practices of effective budget management.', ARRAY[]::TEXT[], NULL),
    ('EDUC-A 695', 'PRACTICUM IN EDUCATIONAL LEADERSHIP', '4356', 'Class Status', NULL, NULL, 'Cassandra Cole', 6, NULL, 'Practicum', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course provides for a closely supervised field experience in various areas of school administration.', ARRAY[]::TEXT[], NULL),
    ('EDUC-A 695', 'PRACTICUM IN EDUCATIONAL LEADERSHIP', '5353', 'Class Status', NULL, 'WB WEB', 'Michele Moore', 10, NULL, 'Practicum', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course provides for a closely supervised field experience in various areas of school administration.', ARRAY[]::TEXT[], NULL),
    ('EDUC-A 695', 'PRACTICUM IN EDUCATIONAL LEADERSHIP', '10534', 'Class Status', NULL, 'WB WEB', 'Nikki Woodson', 21, NULL, 'Practicum', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course provides for a closely supervised field experience in various areas of school administration.', ARRAY[]::TEXT[], NULL),
    ('EDUC-A 754', 'SEMINAR IN RESEARCH IN EDUCATIONAL LEADERSHIP', '30403', 'Class Status', NULL, NULL, 'Frank Perrone', 2, NULL, 'Seminar', '3', NULL, ARRAY[]::TEXT[], 'This course is limited to candidates for the doctorate with a major or minor in educational leadership. The course focuses on study of research design, techniques, and procedures applicable to research problems in administration.', ARRAY[]::TEXT[], NULL),
    ('EDUC-A 799', 'DOCTORAL THESIS IN EDUCATIONAL LEADERSHIP', '9130', 'Class Status', NULL, NULL, 'Frank Perrone', 44, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-A 799', 'DOCTORAL THESIS IN EDUCATIONAL LEADERSHIP', '9131', 'Class Status', NULL, NULL, 'Frank Perrone', 47, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-C 565', 'INTRODUCTION TO COLLEGE AND UNIVERSITY ADMINISTRATION', '5058', 'Class Status', 'W Wednesday 9:10 AM–11:55 AM', 'ED 1225', 'Danielle DeSawal', 16, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Types of institutions and their organization and roles on the nationwide scene: their principal administrative functions, including faculty personnel, business management, public relations, and the liaisons of student personnel with other administrative functions.', ARRAY[]::TEXT[], NULL),
    ('EDUC-C 620', 'PROSEMINAR IN HIGHER EDUCATION', '4477', 'Class Status', 'W Wednesday 3:55 PM–6:35 PM', 'ED 2101', 'Megan Palmer', 21, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course is an introduction to the scholarly study of the field of higher education. Students will be introduced to current issues, theories, forms of inquiry, and disciplinary perspectives relevant to the study of higher education.', ARRAY[]::TEXT[], NULL),
    ('EDUC-C 654', 'HIGHER EDUCATION IN THE UNITED STATES', '8858', 'Class Status', 'Tu Tuesday 5:30 PM–8:00 PM', 'ED 2025 WB WEB', 'Andrea Walton', 11, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU, WEB-BASED CLASS', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-C 675', 'SUPERVISED COLLEGE TEACHING', '1490', 'Class Status', NULL, NULL, 'Cindy Ann Kilgo', 8, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-C 678', 'CAPSTONE IN INSTITUTIONAL RESEARCH', '6006', 'Class Status', 'M Monday 2:20 PM–4:50 PM', 'ED 3269', 'Allison BrckaLorenz', 12, NULL, 'Seminar', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'The IR capstone course provides students with a scholarly understanding of institutional research as well as the skills and abilities required of IR practitioners. It is a project-based course in which students complete a series of projects and produce an electronic portfolio that documents how their skills and knowledge related to the practice of institutional research have developed through course work and applied research experiences.', ARRAY[]::TEXT[], NULL),
    ('EDUC-C 690', 'INDEPENDENT STUDY IN HIGHER EDUCATION', '5979', 'Class Status', NULL, NULL, 'Cindy Ann Kilgo', 9, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Individual research or study with a Higher Education faculty member, arranged in advance of registration. A one or two page written proposal should be submitted to the instructor during the first week of the term, specifying the scope of the project, project activities, meeting times, completion date, and student product(s). Ordinarily, C690 should not be used for the study of material taught in a regularly scheduled course.', ARRAY[]::TEXT[], NULL),
    ('EDUC-C 695', 'ACADEMIC PROBLEMS IN HIGHER EDUCATION', '30456', 'Class Status', 'W Wednesday 12:45 PM–3:30 PM', 'ED 1201', 'Oscar Patrón', 2, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'An examination of academic policies and practices that directly affect faculty. Presents an overview of academic ethics; diversity of institutions; goals and purposes; planning and decision making; governance, trustees and administrators; academic freedom and tenure; faculty roles; student outcomes; student retention; curriculum, teaching and learning; and higher education futures.', ARRAY[]::TEXT[], NULL),
    ('EDUC-C 705', 'LEGAL ASPECTS OF HIGHER EDUCATION', '9902', 'Class Status', NULL, 'WB WEB', 'Jennifer Rippner', 9, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Study of the more important state and federal court decisions affecting facets of the operation and administration of universities, colleges, junior colleges and technical institutes; visible trends in the law of higher education and the underlying philosophies.', ARRAY[]::TEXT[], NULL),
    ('EDUC-C 747', 'PRACTICUM IN ADMINISTRATION', '1491', 'Class Status', NULL, NULL, 'Cindy Ann Kilgo', 4, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Application of theory and knowledge gained in the classroom in an administrative office of a college or university or in an agency related to higher education.', ARRAY[]::TEXT[], NULL),
    ('EDUC-C 750', 'TOPICAL SEMINAR', '35025', 'Class Status', 'F Friday 12:45 PM–3:30 PM', 'ED 2275', 'Thomas Nelson Laird', 3, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Current issues, developments and concerns bearing upon higher education. Specific topics vary each semester.', ARRAY[]::TEXT[], NULL),
    ('EDUC-C 760', 'INTERNSHIP IN ADMINISTRATION', '1492', 'Class Status', NULL, NULL, 'Cindy Ann Kilgo', 5, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Practical application of learning and skills developed during course work by serving, under supervision, as staff members of cooperating college, universities, governmental commissions and educational agencies.', ARRAY[]::TEXT[], NULL),
    ('EDUC-C 788', 'SEMINAR IN RESEARCH IN HIGHER EDUCATION', '3079', 'Class Status', 'Th Thursday 2:20 PM–4:50 PM', 'ED 1235', 'Cindy Ann Kilgo', 2, NULL, 'Seminar', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Study of research design, techniques, and procedures applicable to research problems in administration.', ARRAY[]::TEXT[], NULL),
    ('EDUC-C 788', 'SEMINAR IN RESEARCH IN HIGHER EDUCATION', '37000', 'Closed', NULL, 'WB WEB', 'Cindy Ann Kilgo', 0, NULL, 'Seminar', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Study of research design, techniques, and procedures applicable to research problems in administration.', ARRAY[]::TEXT[], NULL),
    ('EDUC-C 790', 'RESEARCH IN HIGHER EDUCATION', '1493', 'Class Status', NULL, NULL, 'Cindy Ann Kilgo', 10, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'This class is used only for credits needed for semester load requirements (e.g., for international students and assistantship requirements). It is intended for students who are not yet eligible to enroll in dissertation credits.', ARRAY[]::TEXT[], NULL),
    ('EDUC-C 795', 'DISSERTATION PROPOSAL PREP', '10552', 'Class Status', NULL, NULL, 'Cindy Ann Kilgo', 1, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'This course is for the development of a dissertation proposal in Higher Education. Students must have the consent of a dissertation director or prospective dissertation director. Students should be finished or nearly finished with program course work.', ARRAY[]::TEXT[], NULL),
    ('EDUC-C 799', 'DOCTORAL THESIS IN HIGHER EDUCATION', '1494', 'Class Status', NULL, NULL, 'Cindy Ann Kilgo', 63, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-D 505', 'ADULT LEARNING THROUGH THE LIFESPAN', '30242', 'Class Status', NULL, 'OL ONLINE', 'Amy Pickard', 3, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'Study of the adult lifespan with emphasis on the individual in context. Investigate and critically analyze theories and concepts used to understand adult development and lifelong learning including how social and cultural forces influence adult engagement in the learning process.', ARRAY[]::TEXT[], NULL),
    ('EDUC-D 512', 'SEMINAR IN FORMS AND FORCES OF ADULT EDUCATION', '5671', 'Class Status', NULL, 'WB WEB', 'Mary Borst', 10, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The history and current status of adult education in the United States; the nature, scope, purposes, and historical development of adult education institutions and program areas.', ARRAY[]::TEXT[], NULL),
    ('EDUC-D 521', 'PARTICIPATION TRAINING', '6370', 'Class Status', NULL, 'WB WEB', 'Marjorie Treff', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Teambuilding in groups; collaborative program planning and implementation; application of the design to appropriate settings; training in roles of group leader, observer and recorder; recognition and treatment of dysfunctional behaviors in group settings; emphasis on function aspects of group cohesion, consensus decision making, shared leadership, and program evaluation.', ARRAY[]::TEXT[], NULL),
    ('EDUC-D 550', 'PRACTICUM IN ADULT EDUCATION', '5604', 'Class Status', NULL, 'WB WEB', 'Amy Pickard', 20, NULL, 'Lecture', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Supervised practice in instructional planning, teaching, and program development in adult education settings in schools and agencies.', ARRAY[]::TEXT[], NULL),
    ('EDUC-D 590', 'INDEPENDENT STUDY OR RESEARCH IN ADULT EDUCATION', '5605', 'Class Status', NULL, 'WB WEB', 'Amy Pickard', 20, NULL, 'Lecture', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Individual research or study with an Adult Education faculty member, arranged in advance of registration. A one or two page written proposal should be submitted to the instructor during the first week of the term specifying the scope of the project, project activities, meeting times, completion date, and student products.', ARRAY[]::TEXT[], NULL),
    ('EDUC-D 600', 'SEMINAR IN THE TEACHING-LEARNING TRANSACTION IN ADULT EDUCATION', '14115', 'Closed', NULL, 'WB WEB', 'Amy Pickard', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Critical inquiry into the theory of adult learning activities. Includes a review of current research in the adult teaching-learning transaction and the designing and evaluation of individualized instruction for adults.', ARRAY[]::TEXT[], NULL),
    ('EDUC-D 625', 'TOPICAL SEMINAR', '14142', 'Class Status', 'Intersession', 'WB WEB', 'Faridah Pawan', 3, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Systematic study of current issues and problems related to adult education.', ARRAY[]::TEXT[], NULL),
    ('EDUC-D 640', 'CAPSTONE SEMINAR IN ADULT EDUCATION', '6242', 'Class Status', NULL, 'WB WEB', 'Marjorie Treff', 14, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Development of a capstone portfolio that documents the quality of student work in understanding adult education principles, theory and best practices. Students reflect on their growth and development in adult education and describe how they may apply what they have learned.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 225', 'PRINCIPLES OF HISTORY AND SOCIAL SCIENCES IN LEARNING CONTEXTS', '14701', 'Class Status', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'ED 3275', 'Kendra Hazen', 5, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Introduction to fundamental concepts and processes of history and the social sciences, with an emphasis on applications to teaching and learning.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 300', 'ELEMENTARY EDUCATION FOR A PLURALISTIC SOCIETY', '1495', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'ED 3275', 'Anneliese Paulson', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'An overview of the principles of multicultural education. An introduction to major ethnic and minority groups in the United States. A historical review of the status of culturally different learners in elementary schools. A focus upon teaching strategies and curricular innovations for cultural diverse classrooms.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 300', 'ELEMENTARY EDUCATION FOR A PLURALISTIC SOCIETY', '1497', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'ED 2275', 'Kathryn Engebretson', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'An overview of the principles of multicultural education. An introduction to major ethnic and minority groups in the United States. A historical review of the status of culturally different learners in elementary schools. A focus upon teaching strategies and curricular innovations for cultural diverse classrooms.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 300', 'ELEMENTARY EDUCATION FOR A PLURALISTIC SOCIETY', '1496', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'ED 1250', 'Kathy Craig', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'An overview of the principles of multicultural education. An introduction to major ethnic and minority groups in the United States. A historical review of the status of culturally different learners in elementary schools. A focus upon teaching strategies and curricular innovations for cultural diverse classrooms.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 303', 'COMPREHENSIVE CLASSROOM MANAGEMENT', '33894', 'Closed', NULL, 'WB WEB', 'Amnah Alabdulkarim', 0, NULL, 'Independent Study', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Study of effective management strategies and ways to build safe, equitable communities of learning. Course is an asynchronous set of modules. Students work at their own pace through each module. Course includes an interactive discussion component where students must follow a more time sensitive protocol.', ARRAY['Class uses IU eTexts'], NULL),
    ('EDUC-E 303', 'COMPREHENSIVE CLASSROOM MANAGEMENT', '33895', 'Closed', NULL, 'WB WEB', 'Amnah Alabdulkarim', 0, NULL, 'Independent Study', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Study of effective management strategies and ways to build safe, equitable communities of learning. Course is an asynchronous set of modules. Students work at their own pace through each module. Course includes an interactive discussion component where students must follow a more time sensitive protocol.', ARRAY['Class uses IU eTexts'], NULL),
    ('EDUC-E 325', 'SOCIAL STUDIES IN THE ELEMENTARY SCHOOLS', '1498', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'ED 3275', 'Justin Kelsheimer', 2, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Emphasizes the development of objectives, teaching strategies and evaluation procedures that facilitate the social learnings of young children. Special attention given to concept learning, inquiry, decision-making and value analysis.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 325', 'SOCIAL STUDIES IN THE ELEMENTARY SCHOOLS', '7914', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'ED 3275', 'Ling Chen', 4, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Emphasizes the development of objectives, teaching strategies and evaluation procedures that facilitate the social learnings of young children. Special attention given to concept learning, inquiry, decision-making and value analysis.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 325', 'SOCIAL STUDIES IN THE ELEMENTARY SCHOOLS', '12485', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'ED 3275', 'Shirin Reardon', 4, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Emphasizes the development of objectives, teaching strategies and evaluation procedures that facilitate the social learnings of young children. Special attention given to concept learning, inquiry, decision-making and value analysis.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 325', 'SOCIAL STUDIES IN THE ELEMENTARY SCHOOLS', '32305', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'ED 3275', 'Amy Burke', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Emphasizes the development of objectives, teaching strategies and evaluation procedures that facilitate the social learnings of young children. Special attention given to concept learning, inquiry, decision-making and value analysis.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 325', 'SOCIAL STUDIES IN THE ELEMENTARY SCHOOLS', '10360', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'ED 3275', 'Amy Burke', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Emphasizes the development of objectives, teaching strategies and evaluation procedures that facilitate the social learnings of young children. Special attention given to concept learning, inquiry, decision-making and value analysis.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 325', 'SOCIAL STUDIES IN THE ELEMENTARY SCHOOLS', '10362', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'ED 3275', 'Kendra Hazen', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Emphasizes the development of objectives, teaching strategies and evaluation procedures that facilitate the social learnings of young children. Special attention given to concept learning, inquiry, decision-making and value analysis.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 328', 'SCIENCE IN THE ELEMENTARY SCHOOLS', '5145', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'ED 3015', 'Molly Zhang', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'The focus of this course will be on developing teacher competencies in writing performance objectives, question asking, evaluating, and sequencing. These competencies will reveal themselves in the preparation and development of science activities and the teaching strategies involved in presenting those activities to elementary school children.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 328', 'SCIENCE IN THE ELEMENTARY SCHOOLS', '13573', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'ED 3015', 'Alexis Markavage', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'The focus of this course will be on developing teacher competencies in writing performance objectives, question asking, evaluating, and sequencing. These competencies will reveal themselves in the preparation and development of science activities and the teaching strategies involved in presenting those activities to elementary school children.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 335', 'INTRODUCTION TO EARLY CHILDHOOD EDUCATION', '11177', 'Class Status', NULL, 'WB WEB', 'Lauren Ray', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course has a dual focus. First, is an overview of the field including an historic perspective, program models, goals of early childhood education and professional organizations. The second focus emphasizes learning observation skills, understanding the characteristics of young children, teacher-child interaction and classroom management skills.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 335', 'INTRODUCTION TO EARLY CHILDHOOD EDUCATION', '11178', 'Class Status', NULL, 'WB WEB', 'Lauren Ray', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course has a dual focus. First, is an overview of the field including an historic perspective, program models, goals of early childhood education and professional organizations. The second focus emphasizes learning observation skills, understanding the characteristics of young children, teacher-child interaction and classroom management skills.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 336', 'PLAY AS DEVELOPMENT', '11179', 'Class Status', 'Th Thursday 2:20 PM–4:50 PM', 'ED 3025', 'Lauren Ray', 5, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Includes theories and development of play and how it can be guided. Shows how children use play to develop individually, understand the physical, social and cognitive environment, and develop physical and motor skill and creative ability. Includes a section on the selection and construction of play materials.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 341', 'METHODS OF TEACHING READING II', '5975', 'Class Status', NULL, 'WB WEB', 'Lisa Roberts', 10, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course describes and appraises the materials, methods, and techniques employed in diagnostic and corrective instruction in reading programs. Public school participation required.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 343', 'MATH IN THE ELEM SCHOOLS', '13572', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'ED 3017', 'Erin Rich', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Emphasizes the developmental nature of the arithmetic process and its place as an effective tool in the experiences of the elementary school child.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 343', 'MATH IN THE ELEM SCHOOLS', '10726', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'ED 3017', 'Erik Tillema', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Emphasizes the developmental nature of the arithmetic process and its place as an effective tool in the experiences of the elementary school child.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 348', 'FOUNDATIONS OF EARLY CARE AND EDUCATION I: FOCUS ON BIRTH TO AGE 3', '11180', 'Class Status', 'Tu Tuesday 11:10 AM–1:40 PM', 'ED 1004', 'Payal Shah', 5, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Students will examine the foundations of the fields of early childhood education and early intervention. They will explore the teacher/caregiver role; review contemporary theories of best practices with young children; and begin developing the knowledge and skills needed to facilitate healthy growth, development, and learning in all young children.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 352', 'TEACHING AND LEARNING IN PRESCHOOL/KINDERGARTEN', '29891', 'Class Status', 'W Wednesday 3:55 PM–6:35 PM', 'ED 1201', 'Lauren Ray', 4, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course engages students in the development, implementation, and assessment of curricula for all children ages 3-5 years. Content areas of mathematics, social studies, sciences, literacy, and art will be emphasized. Field experience required.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 506', 'CURRICULUM IN EARLY CHILDHOOD', '33139', 'Class Status', NULL, 'OL ONLINE', 'Sharon Dalton', 17, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'Planning the curriculum and selecting and evaluating learning experiences for children ages three through eight years with reference to relevant research. Organizing the classroom to provide maximum integration among experiences in different academic areas.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 525', 'ADVANCED CURRICULUM STUDY IN EARLY CHILDHOOD', '29645', 'Class Status', NULL, 'OL ONLINE', 'Lauren Ray', 7, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'In-depth study of those educators and philosophers, past and present, who have influenced early childhood curricula. Emphasis on the beliefs of Dewey, Piaget, Vygotsky, Montessori, Eisner, and Bruner and how they influence each student''s educational belief system.', ARRAY[]::TEXT[], NULL),
    ('EDUC-E 555', 'HUMAN DIVERSITY IN EDUCATION', '29644', 'Class Status', NULL, 'OL ONLINE', 'Marcus Croom', 1, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'Explores issues related to teaching in a complex and diverse culture. Through this class students will become familiar with a range of diversity issues that teachers confront in our increasingly pluralistic society, including cognitive abilities, learning styles, and cultural, racial, ethnic, and socio-economic backgrounds of children.', ARRAY[]::TEXT[], NULL),
    ('EDUC-F 110', 'WINDOWS ON EDUCATION', '33465', 'Class Status', 'Th Thursday 5:30 PM–7:30 PM', 'ED 1120 ED 1204 ED 1230 ED 1250 ED 1220 ED 2275', 'Patrick McKamy', 42, NULL, 'Lecture', '1', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'First year seminar to support incoming freshmen interested in teaching as a career. The course will facilitate students'' efforts to navigate university life while making an informed decision regarding career choices.', ARRAY[]::TEXT[], NULL),
    ('EDUC-F 110', 'WINDOWS ON EDUCATION', '33470', 'Class Status', 'Tu Tuesday 5:30 PM–7:30 PM', 'ED 1120 ED 1204 ED 1230 ED 1250 ED 1004 ED 2275', 'Patrick McKamy', 9, NULL, 'Lecture', '1', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'First year seminar to support incoming freshmen interested in teaching as a career. The course will facilitate students'' efforts to navigate university life while making an informed decision regarding career choices.', ARRAY[]::TEXT[], NULL),
    ('EDUC-F 203', 'TOPICAL EXPLORATION IN EDUCATION', '12620', 'Class Status', 'Tu Tuesday 5:30 PM–6:20 PM', 'ED 3017', 'Patrick McKamy', 1, NULL, 'Lecture', '1–3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Variable title course.', ARRAY[]::TEXT[], NULL),
    ('EDUC-F 203', 'TOPICAL EXPLORATION IN EDUCATION', '13464', 'Class Status', 'Th Thursday 5:30 PM–6:20 PM', 'ED 2271', 'Patrick McKamy', 13, NULL, 'Lecture', '1–3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Variable title course.', ARRAY[]::TEXT[], NULL),
    ('EDUC-F 203', 'TOPICAL EXPLORATION IN EDUCATION', '12456', 'Class Status', NULL, 'WB WEB', 'Katie Haus', 1, NULL, 'Lecture', '1–3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Variable title course.', ARRAY[]::TEXT[], NULL),
    ('EDUC-F 203', 'TOPICAL EXPLORATION IN EDUCATION', '13802', 'Closed', NULL, NULL, 'Staff', 0, NULL, 'Lecture', '1–3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Variable title course.', ARRAY[]::TEXT[], NULL),
    ('EDUC-F 204', 'SEMINAR INSPIRE LLC', '6296', 'Class Status', 'F Friday 10:25 AM–11:20 AM', 'ED 1120', 'Katie Cierniak', 17, NULL, 'Seminar', '1–3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'The course is designed as a discussion-based seminar where students are guided to explore big, probing questions with education in mind, such as: What does it mean to be a learner and leader at this historical moment in the 21st century? What does it mean to be a part of a learning community? And, how can what I do as a university student help prepare me for a rewarding personal, professional, and public life? In addition to seminar discussions and special guest lectures and presentations from School of Education faculty, students will investigate these questions through a service-learning experience, small group self-directed inquiry projects, and field trips/excursions.', ARRAY[]::TEXT[], NULL),
    ('EDUC-F 204', 'SEMINAR INSPIRE LLC', '6760', 'Class Status', NULL, 'HD TBA', 'Katie Cierniak', 4, NULL, 'Seminar', '1–3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'The course is designed as a discussion-based seminar where students are guided to explore big, probing questions with education in mind, such as: What does it mean to be a learner and leader at this historical moment in the 21st century? What does it mean to be a part of a learning community? And, how can what I do as a university student help prepare me for a rewarding personal, professional, and public life? In addition to seminar discussions and special guest lectures and presentations from School of Education faculty, students will investigate these questions through a service-learning experience, small group self-directed inquiry projects, and field trips/excursions.', ARRAY[]::TEXT[], NULL),
    ('EDUC-F 401', 'TOPICAL EXPLORATION IN EDUCATION', '3216', 'Class Status', NULL, 'WB WEB', 'Staff', 30, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course will explore various topics of relevance to education, both in the United States and abroad.', ARRAY[]::TEXT[], NULL),
    ('EDUC-F 401', 'TOPICAL EXPLORATION IN EDUCATION', '10004', 'Class Status', 'Three Week', 'WB WEB', 'Mike Karlin', 15, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course will explore various topics of relevance to education, both in the United States and abroad.', ARRAY[]::TEXT[], NULL),
    ('EDUC-F 401', 'TOPICAL EXPLORATION IN EDUCATION', '11543', 'Class Status', NULL, 'WB WEB', 'Staff', 15, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course will explore various topics of relevance to education, both in the United States and abroad.', ARRAY[]::TEXT[], NULL),
    ('EDUC-F 401', 'TOPICAL EXPLORATION IN EDUCATION', '14482', 'Closed', NULL, 'WB WEB', 'Susan Drumm', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course will explore various topics of relevance to education, both in the United States and abroad.', ARRAY[]::TEXT[], NULL),
    ('EDUC-F 500', 'TOPICAL EXPLORATION IN EDUCATION', '36225', 'Class Status', 'Tu Tuesday 6:30 PM–8:00 PM', 'OL ONLINE', 'Mike Manis', 8, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'The goal of this course is to bridge the gap between beginning computer users and beginning multimedia developers. The focus of the assignments will be on personal development of strategies and skills to be used in solving problems that arise during multimedia construction. A variety of multimedia software and hardware solutions will be presented including virtual reality, audio and video applications. Student will work on multimedia projects. Some will be undertaken individually while more complex media may involve the formation of teams and/or class projects.', ARRAY[]::TEXT[], NULL),
    ('EDUC-F 500', 'TOPICAL EXPLORATION IN EDUCATION', '4464', 'Class Status', NULL, 'WB WEB', 'Susan Drumm', 1, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'The goal of this course is to bridge the gap between beginning computer users and beginning multimedia developers. The focus of the assignments will be on personal development of strategies and skills to be used in solving problems that arise during multimedia construction. A variety of multimedia software and hardware solutions will be presented including virtual reality, audio and video applications. Student will work on multimedia projects. Some will be undertaken individually while more complex media may involve the formation of teams and/or class projects.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 203', 'COMMUNICATION FOR YOUTH-SERVING PROFESSIONALS', '1503', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'ED 1250', 'Annabel Oertel', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Students study counseling theories and techniques for application to teaching and working with youth. They learn methods of building community and ways to encourage student participation and respect for others. Students learn techniques and attitudes of group dynamics and leadership. Other topics of communication: conlict resolution, active listening, parent-teacher communication.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('EDUC-G 203', 'COMMUNICATION FOR YOUTH-SERVING PROFESSIONALS', '1505', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'ED 1210', 'Taylor Towery', 9, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Students study counseling theories and techniques for application to teaching and working with youth. They learn methods of building community and ways to encourage student participation and respect for others. Students learn techniques and attitudes of group dynamics and leadership. Other topics of communication: conlict resolution, active listening, parent-teacher communication.', ARRAY['IUB GenEd S&H credit'], NULL),
