    ('EDUC-G 203', 'COMMUNICATION FOR YOUTH-SERVING PROFESSIONALS', '11701', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'ED 1220', 'Breeana White', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Students study counseling theories and techniques for application to teaching and working with youth. They learn methods of building community and ways to encourage student participation and respect for others. Students learn techniques and attitudes of group dynamics and leadership. Other topics of communication: conlict resolution, active listening, parent-teacher communication.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('EDUC-G 204', 'ASIAN AMERICAN MENTAL HEALTH', '8942', 'Closed', NULL, 'WB WEB', 'Scarlett Gu', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course addresses issues of Asian American ethnicity, culture, and race as they relate to mental health, psychopathology, and mental health services.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('EDUC-G 206', 'INTRODUCTION TO COUNSELING PSYCHOLOGY', '5501', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'ED 1250', 'Alison Hartong', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course provides an introduction to the fields of counseling and counseling psychology. We will focus mainly on a survey of 11 major theories of counseling and psychotherapy. This course will be useful for students who are interested in the helping professions (e.g., teaching, social work, psychology, counseling, nursing, etc.).', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 206', 'INTRODUCTION TO COUNSELING PSYCHOLOGY', '5539', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'ED 1250', 'Brianna Akers', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course provides an introduction to the fields of counseling and counseling psychology. We will focus mainly on a survey of 11 major theories of counseling and psychotherapy. This course will be useful for students who are interested in the helping professions (e.g., teaching, social work, psychology, counseling, nursing, etc.).', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 206', 'INTRODUCTION TO COUNSELING PSYCHOLOGY', '5538', 'Closed', NULL, 'WB WEB', 'Alison Hartong', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course provides an introduction to the fields of counseling and counseling psychology. We will focus mainly on a survey of 11 major theories of counseling and psychotherapy. This course will be useful for students who are interested in the helping professions (e.g., teaching, social work, psychology, counseling, nursing, etc.).', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 206', 'INTRODUCTION TO COUNSELING PSYCHOLOGY', '8118', 'Closed', NULL, 'WB WEB', 'Taylor Towery', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course provides an introduction to the fields of counseling and counseling psychology. We will focus mainly on a survey of 11 major theories of counseling and psychotherapy. This course will be useful for students who are interested in the helping professions (e.g., teaching, social work, psychology, counseling, nursing, etc.).', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 206', 'INTRODUCTION TO COUNSELING PSYCHOLOGY', '8352', 'Closed', NULL, 'WB WEB', 'Maria D''Ugo', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course provides an introduction to the fields of counseling and counseling psychology. We will focus mainly on a survey of 11 major theories of counseling and psychotherapy. This course will be useful for students who are interested in the helping professions (e.g., teaching, social work, psychology, counseling, nursing, etc.).', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 207', 'INTRODUCTION TO SPORT PSYCHOLOGY AND ATHLETE MENTAL HEALTH', '5502', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'ED 0101', 'Madeline Koch', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Introduces issues related to psychological functioning of student-athletes, and educates future professions (e.g., coaches, administrators, teachers, counselors, academic advisors) working with student-athletes. Provides basic understanding of issues that uniquely impact athletic participants. Students will understand how to identify and access resources that help athletes deal with psychosocial stressors.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 207', 'INTRODUCTION TO SPORT PSYCHOLOGY AND ATHLETE MENTAL HEALTH', '8353', 'Closed', NULL, 'WB WEB', 'Natalie Golub', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Introduces issues related to psychological functioning of student-athletes, and educates future professions (e.g., coaches, administrators, teachers, counselors, academic advisors) working with student-athletes. Provides basic understanding of issues that uniquely impact athletic participants. Students will understand how to identify and access resources that help athletes deal with psychosocial stressors.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 207', 'INTRODUCTION TO SPORT PSYCHOLOGY AND ATHLETE MENTAL HEALTH', '9099', 'Closed', NULL, 'WB WEB', 'Eli Friedman', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Introduces issues related to psychological functioning of student-athletes, and educates future professions (e.g., coaches, administrators, teachers, counselors, academic advisors) working with student-athletes. Provides basic understanding of issues that uniquely impact athletic participants. Students will understand how to identify and access resources that help athletes deal with psychosocial stressors.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 207', 'INTRODUCTION TO SPORT PSYCHOLOGY AND ATHLETE MENTAL HEALTH', '14182', 'Closed', NULL, 'WB WEB', 'Eli Friedman', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Introduces issues related to psychological functioning of student-athletes, and educates future professions (e.g., coaches, administrators, teachers, counselors, academic advisors) working with student-athletes. Provides basic understanding of issues that uniquely impact athletic participants. Students will understand how to identify and access resources that help athletes deal with psychosocial stressors.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 208', 'PREVENTION OF ADOLESCENT RISK BEHAVIOR: COUNSELINGPERSPECTIVES', '5672', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'ED 0101', 'Andrea Mariani', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course will provide an overview of the principles of prevention interventions with a focus on the role of counselors and other helping professionals in the development and dissemination of prevention. Prevention of the following adolescent risk/problems that will be covered in the course: alcohol and drug use, risky sexual behaviors, suicide and self-harm, delinquency, obesity, and bullying. Further, the course will address the settings in which prevention of adolescent risk behaviors occurs including, but not limited to, schools and community agencies.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 272', 'INTRODUCTION TO SEXUALITY COUNSELING', '15079', 'Closed', NULL, 'WB WEB', 'Brianna Akers', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course provides background in the science of sexual anatomy and physiology and then explores some common sex-related problems and empirically-supported treatments for those problems. Application of treatments across diverse populations will be discussed. Students also will be encouraged to think critically about the medicalization of sexual functioning.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 302', 'RESOURCES FOR COUNSELING WITH YOUTH', '5673', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'ED 2025', 'Maria D''Ugo', 5, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course will provide an orientation to the psychological needs of children and adolescents, including but not limited to developing an understanding of potential risk factors as well as the key roles all youth workers and teachers have in helping young people begin to conceptualize their future personal and career goals. Special attention will be given to counseling interventions and the resources available in schools and other community youth-serving agencies. A service-learning component working directly with youth in either a school or local agency is a requirement of this course.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 310', 'ADDICTIONS COUNSELING', '8506', 'Class Status', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'ED 0101', 'Jesus Navarro', 15, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course is a survey of the field of counseling for addictive behaviors. The focus will be largely on alcohol and other drug use. Course topics will include models and theories of addiction, psychological processes and addiction, diversity and health disparities in addiction, and prevention and treatment models. The final portion of the course will cover other non-substance related addictive behaviors such as gambling. Throughout the course, students will be encouraged to challenge common conceptualizations of addictions as portrayed in our society.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 310', 'ADDICTIONS COUNSELING', '8864', 'Closed', NULL, 'WB WEB', 'Jesus Navarro', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course is a survey of the field of counseling for addictive behaviors. The focus will be largely on alcohol and other drug use. Course topics will include models and theories of addiction, psychological processes and addiction, diversity and health disparities in addiction, and prevention and treatment models. The final portion of the course will cover other non-substance related addictive behaviors such as gambling. Throughout the course, students will be encouraged to challenge common conceptualizations of addictions as portrayed in our society.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 310', 'ADDICTIONS COUNSELING', '12880', 'Closed', NULL, 'WB WEB', 'Cintia Alaniz', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course is a survey of the field of counseling for addictive behaviors. The focus will be largely on alcohol and other drug use. Course topics will include models and theories of addiction, psychological processes and addiction, diversity and health disparities in addiction, and prevention and treatment models. The final portion of the course will cover other non-substance related addictive behaviors such as gambling. Throughout the course, students will be encouraged to challenge common conceptualizations of addictions as portrayed in our society.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 310', 'ADDICTIONS COUNSELING', '36751', 'Closed', NULL, 'WB WEB', 'Cintia Alaniz', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course is a survey of the field of counseling for addictive behaviors. The focus will be largely on alcohol and other drug use. Course topics will include models and theories of addiction, psychological processes and addiction, diversity and health disparities in addiction, and prevention and treatment models. The final portion of the course will cover other non-substance related addictive behaviors such as gambling. Throughout the course, students will be encouraged to challenge common conceptualizations of addictions as portrayed in our society.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 332', 'GROUP FACILITATION SKILLS: A COUNSELING PSYCHOLOGY PERSPECTIVE', '11131', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'ED 1230', 'Katy Johnson', 10, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course will provide students with an understanding of the workings and dynamics involved in small groups. By exploring issues (e.g., group leadership, conformity/deviance to norms, groupthink), students can begin to apply knowledge, awareness, and skills within the small group setting to their future personal and professional lives.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 355', 'POSITIVE PSYCHOLOGY', '11130', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'ED 2025', 'Andrea Mariani', 9, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course focuses on the scientific study of what is positive about people and institutions. Historically, psychology has tended to focus on individuals'' pathology, weaknesses, and problems. In contrast, positive psychologists call for greater attention to strengths, happiness, positivity, and that which is worth celebrating. This course presents an overview of theories and research on positive psychology as well explore positive psychological interventions and applications in psychotherapy and in domains relevant to students'' lives, including school, work, family, and romantic relationships.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 355', 'POSITIVE PSYCHOLOGY', '34489', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'ED 1250', 'Jessica Wolf', 6, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course focuses on the scientific study of what is positive about people and institutions. Historically, psychology has tended to focus on individuals'' pathology, weaknesses, and problems. In contrast, positive psychologists call for greater attention to strengths, happiness, positivity, and that which is worth celebrating. This course presents an overview of theories and research on positive psychology as well explore positive psychological interventions and applications in psychotherapy and in domains relevant to students'' lives, including school, work, family, and romantic relationships.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 355', 'POSITIVE PSYCHOLOGY', '8106', 'Class Status', NULL, 'WB WEB', 'Jessica Wolf, Oyku Altintas-Atay', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course focuses on the scientific study of what is positive about people and institutions. Historically, psychology has tended to focus on individuals'' pathology, weaknesses, and problems. In contrast, positive psychologists call for greater attention to strengths, happiness, positivity, and that which is worth celebrating. This course presents an overview of theories and research on positive psychology as well explore positive psychological interventions and applications in psychotherapy and in domains relevant to students'' lives, including school, work, family, and romantic relationships.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 355', 'POSITIVE PSYCHOLOGY', '8354', 'Closed', NULL, 'WB WEB', 'Joshua Jackson', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course focuses on the scientific study of what is positive about people and institutions. Historically, psychology has tended to focus on individuals'' pathology, weaknesses, and problems. In contrast, positive psychologists call for greater attention to strengths, happiness, positivity, and that which is worth celebrating. This course presents an overview of theories and research on positive psychology as well explore positive psychological interventions and applications in psychotherapy and in domains relevant to students'' lives, including school, work, family, and romantic relationships.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 355', 'POSITIVE PSYCHOLOGY', '34498', 'Closed', NULL, 'WB WEB', 'A''Shon Riggins', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course focuses on the scientific study of what is positive about people and institutions. Historically, psychology has tended to focus on individuals'' pathology, weaknesses, and problems. In contrast, positive psychologists call for greater attention to strengths, happiness, positivity, and that which is worth celebrating. This course presents an overview of theories and research on positive psychology as well explore positive psychological interventions and applications in psychotherapy and in domains relevant to students'' lives, including school, work, family, and romantic relationships.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 375', 'MULTICULTURAL COUNSELING-RELATED SKILLS AND COMMUNICATION', '12098', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'ED 2025', 'Mikaila Ealum', 10, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'The course serves as an introduction to multicultural counseling, skills, and communication. We will explore how culture influences behavior and how that knowledge can be applied in counseling-related skills. You will be asked to examine your own culture and how that has shaped your identity and world view as well as how that will impact you as a helping professional. We will also explore other cultures, understand the complexities related to intersectionality, and how this information can be utilized to best meet the needs of different groups.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 375', 'MULTICULTURAL COUNSELING-RELATED SKILLS AND COMMUNICATION', '5946', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'ED 1204', 'Mikaila Ealum', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'The course serves as an introduction to multicultural counseling, skills, and communication. We will explore how culture influences behavior and how that knowledge can be applied in counseling-related skills. You will be asked to examine your own culture and how that has shaped your identity and world view as well as how that will impact you as a helping professional. We will also explore other cultures, understand the complexities related to intersectionality, and how this information can be utilized to best meet the needs of different groups.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 424', 'PROFESSIONAL SKILLS AND CAREER PLANNING IN COUNSELING AND HIGHER EDUCATION', '11156', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'ED 2025', 'Anjali Gottipaty', 10, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Course will focus on exploration of professional skills and career opportunities in the helping professions, e.g., mental health, academic advising, career coaching, student affairs, workplace wellness, and training and development. The overall aim of the course is to assist students in preparing for graduate school, future careers, and life beyond.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 490', 'INDIVIDUAL STUDY IN GUIDANCE', '14858', 'Class Status', NULL, 'HD TBA', 'James Brooks', 8, NULL, 'Independent Study', '1–3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-G 502', 'PROFESSIONAL ORIENTATION AND ETHICS', '11704', 'Class Status', 'W Wednesday 11:10 AM–1:40 PM', 'ED 1084', 'Charla Davis', 4, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Studies that provide and understanding of all aspects of professional functioning including history, roles, organizational structures, ethics, standards, and credentialing.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 502', 'PROFESSIONAL ORIENTATION AND ETHICS', '1506', 'Closed', 'Tu Tuesday 11:10 AM–1:40 PM', 'SB 140', 'Charla Davis', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Studies that provide and understanding of all aspects of professional functioning including history, roles, organizational structures, ethics, standards, and credentialing.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 505', 'INDIVIDUAL APPRAISAL: PRINCIPLES AND PROCEDURES', '11675', 'Class Status', NULL, 'WB WEB', 'Aerin Welch', 3, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'An analysis of statistical, psychometric, socio-metric, and clinical principles crucial to professional interpretation of standardized and informal data regarding individual clients. Current issues/controversies about ethnic, sex, cultural, and individual differences will be examined.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 505', 'INDIVIDUAL APPRAISAL: PRINCIPLES AND PROCEDURES', '13764', 'Class Status', NULL, 'WB WEB', 'Aerin Welch', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'An analysis of statistical, psychometric, socio-metric, and clinical principles crucial to professional interpretation of standardized and informal data regarding individual clients. Current issues/controversies about ethnic, sex, cultural, and individual differences will be examined.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 510', 'INTRODUCTION TO ALCOHOL AND DRUG COUNSELING', '7087', 'Class Status', 'W Wednesday 11:10 AM–1:55 PM', 'ED 1204', 'Ellen Vaughan', 4, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Course is an introduction to social and behavioral theories concerning the causation and maintenance of alcohol and drug addiction. The study and application of research-based theories of counseling will be emphasized. The history of alcohol and drug counseling and recent developments and issues in the field will also be discussed.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 510', 'INTRODUCTION TO ALCOHOL AND DRUG COUNSELING', '15027', 'Class Status', 'Th Thursday 12:45 PM–3:30 PM', 'ED 3015', 'Ellen Vaughan', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Course is an introduction to social and behavioral theories concerning the causation and maintenance of alcohol and drug addiction. The study and application of research-based theories of counseling will be emphasized. The history of alcohol and drug counseling and recent developments and issues in the field will also be discussed.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 513', 'LEGAL AND ILLEGAL DRUGS OF ABUSE', '32530', 'Class Status', NULL, 'OL ONLINE', 'Debolina Ghosh', 10, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'This course deals with the physiological, behavioral, and pharmacological aspects of legal and illegal psychoactive substance use. Special emphasis is placed on observable signs and symptoms resulting from use of psychoactive substances. Attention will also be given to recent trends in psychoactive substance use.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 522', 'COUNSELING THEORIES', '11559', 'Closed', 'M Monday 11:10 AM–1:40 PM', 'ED 0101', 'Lisa Hornibrook', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Introduction to counseling theories and psychological processes involved in individual counseling.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 522', 'COUNSELING THEORIES', '32531', 'Closed', NULL, 'OL ONLINE', 'James Brooks', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Introduction to counseling theories and psychological processes involved in individual counseling.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 523', 'LABORATORY IN COUNSELING AND GUIDANCE', '14643', 'Class Status', 'M Monday 2:20 PM–4:50 PM', 'ED 1201', 'Bo Hyun Lee', 3, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Laboratory experience, counseling, analysis of counseling interviews, role playing and closely supervised counseling in the laboratory setting.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 523', 'LABORATORY IN COUNSELING AND GUIDANCE', '10615', 'Closed', 'Th Thursday 11:10 AM–1:40 PM', 'ED 1004', 'Andres Perez-Rojas', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Laboratory experience, counseling, analysis of counseling interviews, role playing and closely supervised counseling in the laboratory setting.', ARRAY[]::TEXT[], NULL),
