    ('EDUC-G 563', 'MENTAL HEALTH COUNSELING', '1507', 'Class Status', 'Tu Tuesday 5:30 PM–8:00 PM', 'ED 1225', 'Jim Richter', 2, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Foundations and contextual dimensions of mental health counseling. Program development, implementation, and evaluation. Principles, practices, and applications of community needs assessment. Ethics, examination of professional issues, administration, finance and management of mental health counseling services.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 563', 'MENTAL HEALTH COUNSELING', '34950', 'Class Status', NULL, 'WB WEB', 'Jim Richter', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Foundations and contextual dimensions of mental health counseling. Program development, implementation, and evaluation. Principles, practices, and applications of community needs assessment. Ethics, examination of professional issues, administration, finance and management of mental health counseling services.', ARRAY[]::TEXT[], NULL),
