    ('EDUC-G 599', 'THESIS RESEARCH', '3211', 'Class Status', NULL, NULL, 'Sarah Lubienski', 25, NULL, 'Lecture', '0', NULL, ARRAY[]::TEXT[], 'Master''s students who have enrolled in 30 or more hours of graduate course work applicable to the degree and who have completed all other requirements of the degree except the thesis of final project of performance may enroll in G599. Requires section authorization.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 600', 'PRO-SEMINAR IN COUNSELING PSYCHOLOGY', '8865', 'Class Status', 'W Wednesday 9:35 AM–12:05 PM', 'ED 0020', 'Jesse Steinfeldt', 6, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Examination of the history, systems, issues, trends, ethical standards and research findings which impact the role, function and practice of providers of psychological services in the context of counseling.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 622', 'ADVANCED THEORIES OF COUNSELING', '6130', 'Class Status', 'M Monday 11:10 AM–1:40 PM', 'ED 2271', 'Joel Wong', 5, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-G 625', 'ADVANCED PRACTICUM-INDIVIDUAL SUPERVISION', '6243', 'Class Status', NULL, NULL, 'Lauren Laskowski', 17, NULL, 'Practicum', '1–3', NULL, ARRAY[]::TEXT[], 'This course consists of individual supervision for students'' advanced practicum in clinical settings approved by the counseling psychology program. Supervisor provides a minimum of 1 hour per week of face-to face individual supervision, and a formal written evaluation of the supervisee at the end of the semester.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 625', 'ADVANCED PRACTICUM-INDIVIDUAL SUPERVISION', '7396', 'Class Status', NULL, NULL, 'Joel Wong', 17, NULL, 'Practicum', '1–3', NULL, ARRAY[]::TEXT[], 'This course consists of individual supervision for students'' advanced practicum in clinical settings approved by the counseling psychology program. Supervisor provides a minimum of 1 hour per week of face-to face individual supervision, and a formal written evaluation of the supervisee at the end of the semester.', ARRAY[]::TEXT[], NULL),
