    ('EDUC-G 625', 'ADVANCED PRACTICUM-INDIVIDUAL SUPERVISION', '10193', 'Class Status', NULL, NULL, 'Andres Perez-Rojas', 12, NULL, 'Practicum', '1–3', NULL, ARRAY[]::TEXT[], 'This course consists of individual supervision for students'' advanced practicum in clinical settings approved by the counseling psychology program. Supervisor provides a minimum of 1 hour per week of face-to face individual supervision, and a formal written evaluation of the supervisee at the end of the semester.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 647', 'ADVANCED INTERNSHIP IN COUNSELING', '15034', 'Class Status', 'W Wednesday 11:10 AM–1:40 PM', 'ED 0034', 'Rebecca Martinez', 1, NULL, 'Practicum', '1–3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Supervised practice in counseling in various educational or school settings. This field-based experience may be a paid experience for Ed.S. students in counseling. Course partially satisfies counselor licensure requirements.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 647', 'ADVANCED INTERNSHIP IN COUNSELING', '9859', 'Closed', 'Th Thursday 5:30 PM–8:00 PM', 'ED 1235', 'Mia Morrison', 0, NULL, 'Practicum', '1–3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Supervised practice in counseling in various educational or school settings. This field-based experience may be a paid experience for Ed.S. students in counseling. Course partially satisfies counselor licensure requirements.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 647', 'ADVANCED INTERNSHIP IN COUNSELING', '11149', 'Closed', 'F Friday 9:35 AM–12:05 PM', 'ED 0020', 'Timothy Donovan', 0, NULL, 'Practicum', '1–3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Supervised practice in counseling in various educational or school settings. This field-based experience may be a paid experience for Ed.S. students in counseling. Course partially satisfies counselor licensure requirements.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 647', 'ADVANCED INTERNSHIP IN COUNSELING', '13765', 'Closed', 'W Wednesday 5:30 PM–8:00 PM', 'ED 1084', 'Nickolaus Gastil', 0, NULL, 'Practicum', '1–3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Supervised practice in counseling in various educational or school settings. This field-based experience may be a paid experience for Ed.S. students in counseling. Course partially satisfies counselor licensure requirements.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 647', 'ADVANCED INTERNSHIP IN COUNSELING', '9558', 'Closed', 'Tu Tuesday 9:35 AM–12:05 PM', 'ED 0020', 'Bo Hyun Lee', 0, NULL, 'Practicum', '1–3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Supervised practice in counseling in various educational or school settings. This field-based experience may be a paid experience for Ed.S. students in counseling. Course partially satisfies counselor licensure requirements.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 690', 'ADVANCED INDEPENDENT STUDY IN COUNSELING PSYCHOLOGY', '6009', 'Class Status', NULL, NULL, 'Andres Perez-Rojas', 15, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Individual research with a Counseling Psychology faculty member on an advanced counseling topic, arranged prior to registration. A short proposal should be submitted during the first week of the term specifying the scope of the project, completion date, and products. G690 is not for material taught in regularly scheduled courses.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 699', 'INTERNSHIP IN COUNSELING PSYCHOLOGY', '6244', 'Class Status', NULL, NULL, 'Andres Perez-Rojas', 20, NULL, 'Internship', '1–3', NULL, ARRAY[]::TEXT[], 'This is a 12-month full-time internship at a training site approved by the faculty. Training may include individual counseling, couple/family/group therapy, supervision of practicum students, outreach, consultation, and special rotations. Supervision is provided by on-site supervisors, with oversight by course instructor.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 763', 'ADVANCED PRACTICUM IN COUNSELING SUPERVISION', '14590', 'Closed', 'Tu Tuesday 9:35 AM–11:05 AM', 'ED 0034', 'Lauren Laskowski', 0, NULL, 'Practicum', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Closely directed experience in supervising master''s level students in counseling practice in a laboratory, a school, or an agency, plus participation in seminar discussions of the theory and practice of supervision.', ARRAY[]::TEXT[], NULL),
    ('EDUC-G 795', 'DISSERTATION PROPOSAL PREP', '1509', 'Class Status', NULL, NULL, 'Andres Perez-Rojas', 16, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
