    ('EDUC-G 799', 'DOCTORAL THESIS IN COUNSELING PSYCHOLOGY', '1510', 'Class Status', NULL, NULL, 'Andres Perez-Rojas', 28, NULL, 'Independent Study', '1–15', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-G 799', 'DOCTORAL THESIS IN COUNSELING PSYCHOLOGY', '3352', 'Class Status', NULL, NULL, 'Andres Perez-Rojas', 99, NULL, 'Independent Study', '1–15', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-G 901', 'ADVANCED RESEARCH', '1511', 'Class Status', NULL, NULL, 'Thomas Nelson Laird', 49, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate student who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('EDUC-H 205', 'INTRODUCTION TO EDUCATIONAL THOUGHT', '5142', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'ED 2271', 'Quentin Wheeler-Bell', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This introduction to central ideas and Philosophies in the field of educational studies explores questions about the nature of education, its social aims, and the ideas and practices embodied by various approaches to education in order to provide a deeper understanding of what it means to be an educator.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('EDUC-H 205', 'INTRODUCTION TO EDUCATIONAL THOUGHT', '5146', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'ED 2275', 'Quentin Wheeler-Bell', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This introduction to central ideas and Philosophies in the field of educational studies explores questions about the nature of education, its social aims, and the ideas and practices embodied by various approaches to education in order to provide a deeper understanding of what it means to be an educator.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('EDUC-H 205', 'INTRODUCTION TO EDUCATIONAL THOUGHT', '5565', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'ED 1004', 'Kyle O''Brien', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This introduction to central ideas and Philosophies in the field of educational studies explores questions about the nature of education, its social aims, and the ideas and practices embodied by various approaches to education in order to provide a deeper understanding of what it means to be an educator.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('EDUC-H 205', 'INTRODUCTION TO EDUCATIONAL THOUGHT', '5566', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'ED 1002', 'Kyle O''Brien', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This introduction to central ideas and Philosophies in the field of educational studies explores questions about the nature of education, its social aims, and the ideas and practices embodied by various approaches to education in order to provide a deeper understanding of what it means to be an educator.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('EDUC-H 340', 'EDUCATION IN AMERICAN CULTURE', '1512', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'ED 2025', 'Jennifer Rhoda', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'The present educational system, its social and future implications viewed in historical, sociological, and philosophical perspectives. Special attention is given to ethnic, minority, cultural, pluralistic, and legal dimensions of the educational system.', ARRAY[]::TEXT[], NULL),
    ('EDUC-H 340', 'EDUCATION IN AMERICAN CULTURE', '10551', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'ED 1250', 'Jennifer Rhoda', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'The present educational system, its social and future implications viewed in historical, sociological, and philosophical perspectives. Special attention is given to ethnic, minority, cultural, pluralistic, and legal dimensions of the educational system.', ARRAY[]::TEXT[], NULL),
    ('EDUC-H 504', 'HISTORY OF AMERICAN EDUCATION', '12747', 'Class Status', 'Thirteen Week', 'WB WEB', 'Andrea Walton', 7, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-H 520', 'EDUCATION AND SOCIAL ISSUES', '32135', 'Class Status', NULL, 'OL ONLINE', 'Kathleen Kreamelmeyer', 3, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'Identification and analysis of major problems set for education by the pluralistic culture of American society.', ARRAY[]::TEXT[], NULL),
    ('EDUC-H 590', 'INDEPENDENT STUDY OR RESEARCH IN HISTORY, PHILOSOPHY, AND COMPARATIVE EDUCATION', '1514', 'Class Status', NULL, NULL, 'Quentin Wheeler-Bell', 4, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Individual study arranged in advance of registration.', ARRAY[]::TEXT[], NULL),
    ('EDUC-H 590', 'INDEPENDENT STUDY OR RESEARCH IN HISTORY, PHILOSOPHY, AND COMPARATIVE EDUCATION', '5122', 'Class Status', NULL, NULL, 'Quentin Wheeler-Bell', 5, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Individual study arranged in advance of registration.', ARRAY[]::TEXT[], NULL),
    ('EDUC-H 605', 'EDUCATION POLICY AND REFORM', '30405', 'Class Status', 'Th Thursday 3:55 PM–6:25 PM', 'ED 2101', 'Christopher Lubienski', 4, NULL, 'Seminar', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Required introductory course for PhD majors and minors in Education Policy Studies and survey of the field for non-specialists. Covers basic and higher education policies, incorporating a comparative viewpoint. From a sociocultural perspective it explores how power, leadership, organizational dynamics, and social movements interact to define issues and enact policy.', ARRAY[]::TEXT[], NULL),
    ('EDUC-H 795', 'DISSERTATION PROPOSAL PREP', '6420', 'Class Status', NULL, NULL, 'Quentin Wheeler-Bell', 10, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-H 799', 'DOCTORAL THESIS IN THE HISTORY OR PHILOSOPHY OF EDUCATION', '1515', 'Class Status', NULL, NULL, 'Quentin Wheeler-Bell', 13, NULL, 'Research', '1–15', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-H 799', 'DOCTORAL THESIS IN THE HISTORY OR PHILOSOPHY OF EDUCATION', '3361', 'Class Status', NULL, NULL, 'Quentin Wheeler-Bell', 50, NULL, 'Research', '1–15', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-I 251', 'LEARNING THEORIES FOR TEACHERS', '12638', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'ED 1250', 'Srijita Chakraburty', 2, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This is a required course for teacher education majors designed to introduce them to the theories of learning in the context of school learning', ARRAY[]::TEXT[], NULL),
