    ('EDUC-I 251', 'LEARNING THEORIES FOR TEACHERS', '12636', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'ED 1204', 'Daeun Hong', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This is a required course for teacher education majors designed to introduce them to the theories of learning in the context of school learning', ARRAY[]::TEXT[], NULL),
