    ('EDUC-I 251', 'LEARNING THEORIES FOR TEACHERS', '12592', 'Closed', NULL, 'WB WEB', 'Matthew Nussbaum', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This is a required course for teacher education majors designed to introduce them to the theories of learning in the context of school learning', ARRAY[]::TEXT[], NULL),
    ('EDUC-I 540', 'LEARNING AND COGNITION IN EDUCATION', '30243', 'Closed', NULL, 'WB WEB', 'Day Greenberg', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course examines modern cognitive and contemporary sociocultural theories of knowing, learning, and transfer and their implications for teaching, motivating, and assessing learning. It will also briefly consider how those theories and implications are different from other perspectives.', ARRAY[]::TEXT[], NULL),
    ('EDUC-I 632', 'DESIGNING FOR LEARNING IN CONTEXT', '30244', 'Class Status', 'Th Thursday 2:20 PM–4:50 PM', 'ED 1225', 'Daniel Hickey', 8, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This is an advanced seminar in the learning sciences, focused on exploring approach to designing for learning (e.g., Design of Learning Activities). Each specific seminar will have its own focus.', ARRAY[]::TEXT[], NULL),
    ('EDUC-I 632', 'DESIGNING FOR LEARNING IN CONTEXT', '34518', 'Class Status', NULL, 'WB WEB', 'Daniel Hickey', 9, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This is an advanced seminar in the learning sciences, focused on exploring approach to designing for learning (e.g., Design of Learning Activities). Each specific seminar will have its own focus.', ARRAY[]::TEXT[], NULL),
    ('EDUC-I 674', 'ADVANCED TOPICAL SEMINAR IN LEARNING SCIENCES', '30245', 'Class Status', 'W Wednesday 11:10 AM–1:40 PM', 'ED 1235', 'Day Greenberg', 7, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Topical seminar for doctoral students in Learning Sciences. Possible topics include online instruction, computers in education, activity theory, problem based learning, embodied cognition, gaming/simulation, AI in Education, computational thinking and problem solving to name a few. We allow repetition so long as each section is a different topic.', ARRAY[]::TEXT[], NULL),
    ('EDUC-I 674', 'ADVANCED TOPICAL SEMINAR IN LEARNING SCIENCES', '30246', 'Class Status', NULL, 'WB WEB', 'Daniel Hickey', 9, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Topical seminar for doctoral students in Learning Sciences. Possible topics include online instruction, computers in education, activity theory, problem based learning, embodied cognition, gaming/simulation, AI in Education, computational thinking and problem solving to name a few. We allow repetition so long as each section is a different topic.', ARRAY[]::TEXT[], NULL),
    ('EDUC-I 799', 'DOCTORAL THESIS IN LEARNING SCIENCES', '30250', 'Class Status', NULL, NULL, 'Daniel Hickey', 13, NULL, 'Independent Study', '1–12', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course is to be taken while completing a dissertation in Learning Sciences.', ARRAY[]::TEXT[], NULL),
    ('EDUC-I 799', 'DOCTORAL THESIS IN LEARNING SCIENCES', '30247', 'Class Status', NULL, 'WB WEB', 'Daniel Hickey', 14, NULL, 'Independent Study', '1–12', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course is to be taken while completing a dissertation in Learning Sciences.', ARRAY[]::TEXT[], NULL),
    ('EDUC-J 500', 'INSTRUCTION IN THE CONTEXT OF CURRICULUM', '30391', 'Class Status', NULL, 'WB WEB', 'Daniel Castner', 12, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'First course for the Master''s degree in Curriculum & Instruction. Extends concepts introduced in undergraduate teacher preparation. Topics include conceptions and definitions of curriculum and instruction and their impact on social contexts, learning theories, and schooling practices. Elementary and secondary contexts are studied.', ARRAY[]::TEXT[], NULL),
    ('EDUC-J 500', 'INSTRUCTION IN THE CONTEXT OF CURRICULUM', '33146', 'Class Status', NULL, NULL, 'Rachel Star', 14, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'First course for the Master''s degree in Curriculum & Instruction. Extends concepts introduced in undergraduate teacher preparation. Topics include conceptions and definitions of curriculum and instruction and their impact on social contexts, learning theories, and schooling practices. Elementary and secondary contexts are studied.', ARRAY[]::TEXT[], NULL),
    ('EDUC-J 502', 'ASSESSMENT AND EVALUATION', '29641', 'Closed', NULL, 'WB WEB', 'Erik Jacobson', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'An introductory course for education professionals. Topics of study include principles of assessment, formal/informal assessment instruments and methods, formative & summative assessment, interpretation/use of standardized test results, social/political issues in assessment, and analysis of data. Evaluation topics include determining eligibility for special ed, evaluation of programs, and instructional approaches.', ARRAY[]::TEXT[], NULL),
    ('EDUC-J 605', 'INDEPENDENT RESEARCH EXPERIENCE IN CURRICULUM AND INSTRUCTION', '4700', 'Class Status', NULL, NULL, 'Keith Barton', 8, NULL, 'Independent Study', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Provides doctoral students an opportunity to work closely with faculty in pursuing an individual research project early in their program.', ARRAY[]::TEXT[], NULL),
    ('EDUC-J 605', 'INDEPENDENT RESEARCH EXPERIENCE IN CURRICULUM AND INSTRUCTION', '5674', 'Class Status', NULL, 'WB WEB', 'Amy Hackenberg', 9, NULL, 'Independent Study', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Provides doctoral students an opportunity to work closely with faculty in pursuing an individual research project early in their program.', ARRAY[]::TEXT[], NULL),
    ('EDUC-J 605', 'INDEPENDENT RESEARCH EXPERIENCE IN CURRICULUM AND INSTRUCTION', '14671', 'Class Status', NULL, 'WB WEB', 'Kevin Tavin', 4, NULL, 'Independent Study', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Provides doctoral students an opportunity to work closely with faculty in pursuing an individual research project early in their program.', ARRAY[]::TEXT[], NULL),
    ('EDUC-J 650', 'INDEPENDENT STUDY IN CURRICULUM', '1517', 'Class Status', NULL, NULL, 'Keith Barton', 10, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Independent study of a selected topic under the guidance of a faculty member.', ARRAY[]::TEXT[], NULL),
    ('EDUC-J 690', 'INTERNSHIP IN CURRICULUM', '1518', 'Class Status', NULL, NULL, 'Keith Barton', 4, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-J 700', 'TEACHING IN TEACHER EDUCATION', '35184', 'Closed', 'W Wednesday 3:55 PM–6:40 PM', 'ED 1004', 'Alexander Cuenca', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Emphasis on pedagogical methods and student learning styles in higher education, applied to one''s current or future course development and instruction. Topics will focus on application of teaching and field supervision methods in the context of literature review, observation, reflection, class discourse, and continual professional development.', ARRAY[]::TEXT[], NULL),
    ('EDUC-J 705', 'SEMINAR: INQUIRY IN CURRICULUM AND INSTRUCTION', '8672', 'Class Status', 'F Friday 11:10 AM–1:40 PM', 'ED 3115', 'Keith Barton', 9, NULL, 'Seminar', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Intended for students at a stage in their doctoral programs that requires them to begin conceptualizing their own doctoral dissertation research. Emphasis will be on analyzing and synthesizing a body of research in one or more of the specialized fields of study within curriculum and instruction.', ARRAY[]::TEXT[], NULL),
    ('EDUC-J 705', 'SEMINAR: INQUIRY IN CURRICULUM AND INSTRUCTION', '14672', 'Class Status', NULL, 'WB WEB', 'Kevin Tavin', 3, NULL, 'Seminar', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Intended for students at a stage in their doctoral programs that requires them to begin conceptualizing their own doctoral dissertation research. Emphasis will be on analyzing and synthesizing a body of research in one or more of the specialized fields of study within curriculum and instruction.', ARRAY[]::TEXT[], NULL),
    ('EDUC-J 730', 'ADVANCED CURRICULUM THEORY', '35183', 'Class Status', 'Tu Tuesday 8:00 AM–10:30 AM', 'ED 3017', 'Keith Barton', 3, NULL, 'Seminar', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Critical analysis of selected contemporary curriculum and instructional discourses. Particular attention is given to theorizing during the last twenty-five years.', ARRAY[]::TEXT[], NULL),
    ('EDUC-J 760', 'TOPICAL SEMINAR IN CURRICULUM AND INSTRUCTION ISSUES', '14110', 'Class Status', NULL, 'WB WEB', 'Patricia Kubow', 3, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Intended for advanced graduate students in curriculum and instruction; emphasizes analysis and appraisal of curriculum and reform efforts in terms of persistent, critical issues in education. Opportunities are provided to study trends and issues with reference to various specialties of students enrolled.', ARRAY[]::TEXT[], NULL),
